import React, { useState, useEffect } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faAngleLeft, faCode, faDesktop, faEnvelope } from '@fortawesome/free-solid-svg-icons';
// import data from '../../data/projects.json';
import './Project.css';

const Project = ({ projData, onClick }) => {
    // const allProjects = data.projects;
    // const [currentProject, setCurrentProject] = useState({});
    // const [pie, setPie] = useState([]);
    // useEffect(() => {
    //     matchProject();
    // });
    // const projectMainImage = require(projData.projectImages.mainImage);
    // const asdfasdf = require("../../assets/images/das.jpg")


    useEffect(() => {

    });

    const handleSetContainer = () => {
        onClick(true);
    }

    // const matchProject = () => {
    //     allProjects.map((project) => {
    //         if (project.slug === projData) {
    //             setCurrentProject(project);
    //             // setPie(project.technologies);

    //         }
    //         return ' ';
    //     });

    // }

    const currentTechnologiesLists = () => {
        // if(currentProject.technologies){
        //     return currentProject.technologies.map((indiPie, i) => {
        //         return <li key={i}>hello</li>
        //     });
        // }


        return projData.technologies.map((indivTechnology, i) => {
            return <li key={i}>{indivTechnology}</li>
        });
    }

    return (
        <div className="project">
            <div className="project-main-container">
                <div className="project-back-button">
                    <div className="back-button" onClick={handleSetContainer}>
                        <FontAwesomeIcon className="font-awsome-close-btn" icon={faAngleLeft} size="2x" color="#ffa500"/>
                    </div>
                </div>
                <div className="project-name">
                    <h6>{projData.title}</h6>
                </div>
                <div className="project-content">

                    <div className="project-content--images">
                        <div className="project-image-one image-container">
                            <img src={require(`../../assets/images/${projData.projectImages.mainImage}.jpg`)} alt={projData.projectImages.mainImage} />
                        </div>
                        <div className="project-image-two image-container">
                            <img src={require(`../../assets/images/${projData.projectImages.subImages[0]}.jpg`)} alt={projData.projectImages.subImages[0]} />
                        </div>
                        <div className="project-image-three image-container">
                            <img src={require(`../../assets/images/${projData.projectImages.subImages[1]}.jpg`)} alt={projData.projectImages.subImages[1]} />
                        </div>
                        <div className="project-image-four image-container">
                            <img src={require(`../../assets/images/${projData.projectImages.subImages[2]}.jpg`)} alt={projData.projectImages.subImages[2]} />
                        </div>
                    </div>
                    <div className="project-content--project-information">
                        <div className="project-technologies">
                            <h6>Technologies used:</h6>
                            <ul>
                                {
                                    currentTechnologiesLists()

                                }
                            </ul>
                        </div>
                        <div className="project-descriptions">
                            <h6>About the project:</h6>
                            <p>{projData.description}</p>
                        </div>
                        <div className="project-links">
                            <div className="code-btn-link project-btn-links">
                                <a href={projData.projectCode} target="_blank" rel="noopener noreferrer"><FontAwesomeIcon className="font-awsome-code-btn font-awsome-project-btn-links" icon={faCode} size="3x" color="#ffa500" /></a>
                            </div>
                            <div className="webpage-btn-link project-btn-links">
                                <FontAwesomeIcon className="font-awsome-webpage-btn font-awsome-project-btn-links" icon={faDesktop} size="3x" color="#ffa500" />
                            </div>
                            <div className="contact-btn-link project-btn-links">
                                <FontAwesomeIcon className="font-awsome-contact-btn font-awsome-project-btn-links" icon={faEnvelope} size="3x" color="#ffa500" />
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        </div>
    )
}

export default Project;
