import React from 'react';
import './Title.css';

const Title = ({title}) => {
    const currentScreenTitle = title.toLowerCase(); 
    return (
        <div className="title-contents">
            <div className={`${currentScreenTitle}-title screen-title`}>
                <h1>{title}</h1>
            </div>
        </div>
    )
}

export default Title;
