import React, { useState, useEffect } from 'react';
import './App.css';
import Header from '../header/Header';
import Home from '../home/Home';



const App = () => {
  const [windowWidth, setWindowWidth] = useState(null);
  useEffect(() => {
    const windowWidthFirstCheck = setTimeout(() => {
      currentWindowWidth();
    }, 100);
    window.addEventListener("resize", currentWindowWidth);
    return () => {
      window.removeEventListener("resize", currentWindowWidth);
      clearTimeout(windowWidthFirstCheck);
    }
  }, [windowWidth]);

  const currentWindowWidth = () => {
    const disableViewResolution = (window.innerWidth > 2560 || window.innerWidth < 350);
    setWindowWidth(disableViewResolution);
  }

  const limitBrowserWidth = () => {
    if (windowWidth) {
      // Create another component here for showing the message if the resolution is over 2k and is below 350px
      return (<div>{`The browser is a 2k and above monitor: ${windowWidth}`}</div>)
    } else {
      return (
        <React.Fragment>
          <Header />
          <Home />
        </React.Fragment>

      )
    }
  }
  return (
    <div className="App">
      {limitBrowserWidth()}
    </div>
  );
}

export default App;
